<script>
    var popUpNotification = $(""#WSNotification"").data(""kendoNotification"");

    $('#AlhajjMasterForm').submit(function (e) {

        e.preventDefault();
        if ($(""#NIC"").val() == 'لايوجد') {
            $(""#NIC"").addClass(""border border-danger"");
        }

        $.ajax({
            url: this.action,    //Url.Action(""GetAlhajjDataFormWebService"", ""AlhajjMasters"")
            type: this.method,
            data: $(this).serialize(),  // { ServiceNumber: $(""#ServiceNumber"").val() }
            //   dataType: ""JSON"",
            success: function (data) {

                popUpNotification.show(kendo.toString(""تمت الإضافة بنجاح""), ""info"");
                $(""#ServiceNumber"").val("""");

            },
            error: function (xhr, status, error) {

                console.log(xhr);
                popUpNotification.show(kendo.toString(xhr.responseText), ""error"");



            }



        });

    });

</script>");
